// Project/ZeroCommon/Llm/Tools/LocalAgentLoop.cs
private async Task<string> ExecuteToolAsync(ToolCall call, CancellationToken ct)
{
    switch (call.Tool)
    {
        case "list_terminals":   return await _host.ListTerminalsAsync(ct);
        case "read_terminal":    return await _host.ReadTerminalAsync(g, t, n, ct);
        case "send_to_terminal": return await _host.SendToTerminalAsync(g, t, text, ct);
        case "send_key":         return await _host.SendKeyAsync(g, t, key, ct);
        case "wait":             await Task.Delay(seconds, ct); return ok;
        // "done" is intercepted before this switch — terminal of the run.
    }
}
